#include<bits/stdc++.h>
using namespace std;

int main(){
    int m,n,ans=0;
    cin>>m>>n;
    for(int i=1;i<=m;i++){
        for(int j=1;j<=n;j++){
            int c;
            cin>>c;
            if(i==1||j==1||i==m||j==n){
                ans+=c;
            }

        }
    }
    cout<<ans;
    return 0;
}
